INSERT INTO construction_knowledge (content, category, subcategory, source, metadata) VALUES
('OHS Act 85 of 1993: Section 16 - Chief Executive Officer duties. The CEO shall ensure that the duties of the employer are properly discharged. Penalties for non-compliance: fine up to R500,000 or imprisonment up to 1 year.', 'law', 'OHS Act', 'OHS Act 85/1993', '{"act": "OHS Act 85/1993", "section": "16", "penalty": "R500,000"}'),
('Construction Regulations 2014: Regulation 2 - Duties of clients. Client must prepare a baseline risk assessment for the project, appoint a PHS officer for projects > R13m.', 'law', 'Construction Regs 2014', 'Govt Gazette No. 2014', '{"regulation": "Reg 2", "subject": "Client Duties", "threshold": "R13 million"}'),
('Construction Regulations 2014: Regulation 5 - Duties of principal contractor. Must ensure all contractors comply with OHS Act, conduct regular site audits, maintain H&S file, develop site-specific H&S plan.', 'law', 'Construction Regs 2014', 'Govt Gazette No. 2014', '{"regulation": "Reg 5", "subject": "Principal Contractor"}'),
('COIDA: All employers must register with the Compensation Fund. Claims must be submitted within 14 days of incident. Coverage includes medical expenses, temporary total disablement, permanent disablement, death benefits.', 'law', 'COIDA', 'COIDA Act 130/1993', '{"act": "COIDA", "registration": "mandatory", "claim_window": "14 days"}'),
('FIDIC Red Book 2017: Conditions of Contract for Construction. Key clauses: 3 (Engineer), 8 (Time for Completion), 13 (Variations), 14 (Payment), 20 (Claims). Sub-clause 20.1: Contractor must give notice of claim within 28 days.', 'law', 'FIDIC', 'FIDIC 2017', '{"standard": "FIDIC 2017", "type": "Red Book", "claim_period": "28 days"}'),
('GCC 2015: Clause 52 - Variations and Valuation. Clause 44 - Extension of Time. Clause 45 - Penalties. Must be read with COLTO or SANS 4000 for measurement.', 'law', 'GCC', 'GCC 2015', '{"standard": "GCC 2015", "country": "South Africa"}'),
('NEC4 ECC: Clause 60 - Compensation Events. Clause 61 - Notification. Clause 62 - Quotations. Clause 15 - Early warning: Contractor must notify PM of any matter that could affect time, cost, or quality.', 'law', 'NEC', 'NEC4 ECC', '{"standard": "NEC4"}'),
('JBCC Principal Building Agreement 2018: Clauses: 23 (Payment), 24 (Completion), 25 (Penalties), 26 (Defects), 27 (Insurance), 28 (Dispute Resolution).', 'law', 'JBCC', 'JBCC 2018', '{"standard": "JBCC 2018", "country": "South Africa"}'),
('HIRA Methodology: Hazard Identification and Risk Assessment. Step 1 - Identify hazards. Step 2 - Determine risk (Likelihood x Severity). Step 3 - Evaluate risk level. Step 4 - Identify control measures (hierarchy: Eliminate > Substitute > Engineering > Admin > PPE). Step 5 - Implement and monitor.', 'safety', 'Risk Assessment', 'OHS Act', '{"method": "HIRA", "steps": "5"}'),
('Fall Protection Plan (Construction Regs 2014 Reg 10): risk assessment for all working-at-height activities, hierarchy of controls, anchor point specification, rescue plan, training requirements.', 'safety', 'Working at Height', 'Con Regs 2014', '{"regulation": "Reg 10", "focus": "Fall Protection"}'),
('Scaffolding (Reg 15): Scaffold must be designed by competent person, erected by trained erectors, inspected before use and weekly. Tag system: Green (Safe), Yellow (Conditional), Red (Unsafe).', 'safety', 'Scaffolding', 'Con Regs 2014', '{"regulation": "Reg 15"}'),
('PPE hierarchy: 1) Eliminate, 2) Substitute, 3) Engineering controls, 4) Administrative controls, 5) PPE. Mandatory on SA sites: Hard hat (SANS 1397), Safety boots (SANS 1705), High-vis vest (SANS 1398).', 'safety', 'PPE', 'OHS Act', '{"standard": "SANS", "type": "PPE"}'),
('Toolbox Talks: weekly, minimum 15 minutes. Documented with date, topic, presenter, attendees, discussion summary. 20 essential topics including Working at Height, Manual Handling, Fire Safety, Electrical Safety, PPE, Excavation, Scaffold.', 'safety', 'Toolbox Talks', 'Industry Best Practice', '{"frequency": "weekly", "duration": "15 min"}'),
('Incident Investigation - ICAM: 1) Secure scene, 2) Collect evidence, 3) Identify immediate causes, 4) Identify underlying causes, 5) Identify root causes, 6) Develop corrective actions. OHS Act Section 24 requires reporting within 7 days.', 'safety', 'Incidents', 'ICAM Methodology', '{"method": "ICAM", "reporting": "Section 24"}'),
('Safety file contents (Reg 7): Project description, baseline risk assessment, H&S specifications, H&S plan, risk assessments, method statements, safe work procedures, medicals, training records, registers, incident reports, legal appointments, COIDA.', 'safety', 'Safety File', 'Con Regs 2014 Reg 7', '{"regulation": "Reg 7", "type": "Safety File"}'),
('Legal appointments required: Section 16(2) appointee, Section 8(1) appointee, Construction Manager, H&S Officer (SACPCMP for > R13m), H&S Supervisor, First Aiders (1 per 50), Fire Fighters, H&S Reps.', 'safety', 'Legal Appointments', 'OHS Act', '{"type": "legal appointments"}'),
('Emergency preparedness: Emergency Action Plan, evacuation routes, assembly points, first aid station, emergency contacts, fire extinguishers, emergency drills (quarterly), spill response kit.', 'safety', 'Emergency', 'OHS Act', '{"type": "emergency preparedness"}'),
('Designer duties (Reg 8): Structure must be safe to construct, maintain, and demolish. Provide safety information with tender documents. SANS 10400 compliance mandatory.', 'safety', 'Designer Duties', 'Con Regs 2014', '{"regulation": "Reg 8"}'),
('SANS 4000: Standard Method of Measurement for Civil Engineering Works. Defines measurement rules for Earthworks, Concrete, Steel reinforcement, Road construction, Drainage. All items measured net.', 'surveying', 'Measurement', 'SANS 4000', '{"standard": "SANS 4000"}'),
('Cost estimation methods: Class 5 (+/-50%) concept, Class 4 (+/-30%) budget, Class 3 (+/-15%) detailed, Class 2 (+/-10%) tender, Class 1 (+/-5%) as-built.', 'surveying', 'Cost Estimation', 'AACE International', '{"method": "AACE Classification", "classes": "5"}'),
('P&G items typically 10-15% of project value for building and 12-20% for civils. Includes site establishment, offices, security, scaffolding, plant, safety, insurances, professional fees.', 'surveying', 'P&G', 'ASAQS Practice Manual', '{"type": "P&G", "range": "10-20%"}'),
('Contingency allowances: Design & Build 5-10%, Traditional 5-7.5%, Renovations 10-15%, Infrastructure 10-20%. Must be justified against risk register.', 'surveying', 'Contingency', 'ASAQS Practice Manual', '{"type": "contingency", "range": "5-20%"}'),
('Construction cost breakdown: Substructure 8-12%, Superstructure 35-45%, Finishes 15-20%, Services 15-25%, External Works 5-10%, Prelims 10-15%. Labour:Materials ratio 40:60 building, 30:70 civils.', 'surveying', 'Cost Breakdown', 'ASAQS 2024', '{"type": "typical breakdown"}'),
('Variation valuation (FIDIC Clause 13.3): by agreed rates or new rates based on actual costs plus reasonable profit. Variations exceeding 15% trigger rate adjustment.', 'surveying', 'Variations', 'FIDIC GCC JBCC', '{"type": "variations", "threshold": "15%"}'),
('Final account procedure: 1) Draft within 3 months of practical completion, 2) Submit with supporting docs, 3) Agree, 4) Issue final certificate, 5) Release retention (5%, 6-12 months).', 'surveying', 'Final Account', 'ASAQS Procedure', '{"type": "final account", "retention": "5%"}'),
('SANS 10400: Parts A (Administration), B (Structural), C (Dimensions), D (Public Safety), F (Site Ops), G (Excavations), H (Foundations), J (Floors), K (Walls), L (Roofs), N (Glazing), O (Lighting), P (Drainage), T (Fire Protection), W (Fire Installations).', 'architecture', 'SANS 10400', 'SANS 10400', '{"standard": "SANS 10400", "parts": "A-W"}'),
('Concrete design to SANS 10100-1: Grades 20MPa to 50MPa. Cover: Mild 20mm, Moderate 30mm, Severe 40mm, Very severe 50mm. Min reinforcement 0.13% of cross-section.', 'architecture', 'Concrete Design', 'SANS 10100-1', '{"standard": "SANS 10100-1"}'),
('Steel design to SANS 10162: Section classes 1-4. Bolted connections Grade 4.6, 8.8, 10.9. Welding to SANS 10163. Fire protection: 1hr for 2-storey, 2hr for high-rise.', 'architecture', 'Steel Design', 'SANS 10162', '{"standard": "SANS 10162"}'),
('COLTO 2024: SA road construction specs. Sections: 1000 Earthworks, 2000 Materials, 3000 Pavement Layers, 4000 Base/Subbase, 5000 Asphalt, 6000 Concrete Road, 7000 Bridgeworks, 8000 Drainage. G classes G1-G10.', 'engineering', 'COLTO', 'COLTO 2024', '{"standard": "COLTO", "year": "2024"}'),
('Concrete pricing 2024: Grade 20 R1,750-1,950/m3, Grade 25 R1,850-2,050/m3, Grade 30 R2,000-2,200/m3, Grade 35 R2,150-2,400/m3, Grade 40 R2,350-2,600/m3. Delivery up to 30km included.', 'materials', 'Concrete', 'ASAQS 2024', '{"category": "concrete", "year": "2024"}'),
('Steel reinforcement 2024: Y10 R13,000-15,000/ton, Y12 R12,800-14,500/ton, Y16 R12,500-14,200/ton, Y20 R12,300-14,000/ton. Mesh A142 R180-200/sheet.', 'materials', 'Steel Reinforcement', 'SAFCEC 2024', '{"category": "reinforcement", "year": "2024"}'),
('Structural steel 2024: Universal beams R15,000-18,000/ton, Columns R14,500-17,000/ton, Angles R13,500-16,000/ton, Hollow sections R16,000-19,000/ton. Galvanizing add R4,000-6,000/ton.', 'materials', 'Structural Steel', 'Macsteel 2024', '{"category": "steel", "source": "Macsteel"}'),
('Labour rates 2024 (BCEA): Skilled artisan R45-65/hr, Semi-skilled R28-38/hr, General worker R22-28/hr. Total employment cost = basic x 1.37 to 1.65 (incl UIF, COIDA, SDL, leave, bonus, pension).', 'materials', 'Labour Rates', 'BCEA 2024', '{"category": "labour", "year": "2024"}'),
('Plant hire 2024 per hour: Excavator 20t R550-700, TLB R380-500, Grader R650-850, Roller 10t R450-600, Crane 25t R850-1,100, Water truck R350-450, Tipper R320-420. Min hire 8hrs/day.', 'materials', 'Plant Hire', 'SA Plant Hire 2024', '{"category": "plant", "year": "2024"}'),
('Road construction materials 2024: G5 base delivered R180-250/m3, G6 subbase R140-200/m3, G7 selected R100-160/m3. Asphalt wearing 30mm R160-200/m2.', 'materials', 'Road Construction', 'COLTO/SANRAL 2024', '{"category": "roadworks", "year": "2024"}'),
('Crane safety: SWL applies 360 degrees. Outriggers deployed on firm level ground. Daily inspection: wire rope, hooks, safety latches, limit switches. Wind speed limit 14m/s. Operator certification required.', 'plant', 'Crane Safety', 'SANS 10160', '{"category": "cranes", "standard": "SANS 10160"}'),
('Mobile plant pre-use checks: fluids, tyres/tracks, lights/horn/alarm, mirrors, fire extinguisher, seatbelt, ROPS/FOPS, controls, brakes, hoses, bucket. Daily log required. Defect = tag out.', 'plant', 'Plant Inspection', 'Industry Standard', '{"type": "pre-use inspection", "frequency": "daily"}'),
('Compressed air safety: Max working pressure 7-10 bar. Safety valves set at 10% above. Receiver inspection every 24 months. Never point at skin. Whip checks on couplings.', 'plant', 'Compressors', 'OHS Act', '{"type": "compressed air"}'),
('DoEL inspections: Inspector enters without notice. Can take photos, documents, samples, interview. Prohibition Notice (stop work), Contravention Notice (remedy by date). Appeal within 30 days.', 'regulations', 'DoEL Inspections', 'OHS Act Section 36', '{"authority": "DoEL", "type": "inspections"}'),
('SACPCMP registration: CHSE, CHSM, CHSO categories. Requires Diploma/Degree + 3 years + SAQA + interview + 20 CPD points/year. Projects > R13m require SACPCMP registered H&S Agent.', 'regulations', 'SACPCMP', 'SACPCMP Rules', '{"body": "SACPCMP", "categories": "CHSE/CHSM/CHSO"}'),
('NEMA: Listed activities requiring EIA - roads > 1km, dams > 100,000m3, pipelines > 1km, residential > 3ha, industrial > 1ha. EMP required for all construction. Hazardous waste manifests.', 'regulations', 'NEMA', 'NEMA 107/1998', '{"act": "NEMA 107/1998"}'),
('CIDB grading: Grade 1 (R1.5m) to 9 (R1bn+). Categories: CE, GB, ME, EB, EP, SW. Required for public sector tenders. PE for professional services.', 'regulations', 'CIDB', 'CIDB Act 38/2000', '{"body": "CIDB", "grades": "1-9"}')
